mapper.select:
select id, title, start_time, end_time, longitude, latitude, radius, target_classes, create_user_id, create_time, update_time
from t_activity


        and title like concat('%', #{title}, '%')


        and start_time >= #{startTime}


        and end_time <= #{endTime}


        and target_classes like concat('%', #{targetClasses}, '%')

    and create_user_id = #{createUserId}

order by create_time desc
